SELECT COUNT(*) AS quantidade_servidores FROM SERVIDOR S WHERE LOWER(S.AREA_INGRESSO) = LOWER('sociologia') AND LOWER(S.SIGLA_CAMPUS) = LOWER('for') AND SAIU_DO_IFG = FALSE AND (DATA_INGRESSO_IFG IS NULL OR (CAST(strftime('%Y', DATA_INGRESSO_IFG) AS INTEGER) < 2020 OR (CAST(strftime('%Y', DATA_INGRESSO_IFG) AS INTEGER) = 2020 AND CAST(strftime('%m', DATA_INGRESSO_IFG) AS REAL) <= 6)))